// Extract attendee info from calendar event to identify client
const event = $input.all()[0].json;
const attendees = (event.attendees || []).map(a => a.email).filter(e => e);
const domains = attendees.map(e => e.split('@')[1]).filter(d => !d.includes('gmail.com') && !d.includes('google.com'));

const startTime = new Date(event.start?.dateTime || event.start?.date);
const endTime = new Date(event.end?.dateTime || event.end?.date);
const durationMin = Math.round((endTime - startTime) / 60000);

return [{
  json: {
    event_id: event.id,
    event_title: event.summary || 'Untitled Meeting',
    meeting_datetime: event.start?.dateTime || event.start?.date,
    meeting_duration: durationMin,
    attendees: attendees.join(', '),
    attendee_domains: [...new Set(domains)],
    event_description: event.description || '',
    manual_notes: event.description || '',
    lookup_type: 'email_domain',
    lookup_value: domains[0] || 'unknown'
  }
}];

// Gather all inputs for agenda generation
const eventInfo = $('Extract Event Info').first().json;
const clientData = $('Client Lookup').first().json;
const spaceId = clientData.clickup_space_id;

// Fetch open tasks from ClickUp
const openTasksRaw = await this.helpers.httpRequest({
  method: 'GET',
  url: `https://api.clickup.com/api/v2/team/9011968555/task?space_ids[]=${spaceId}&include_closed=false`,
  headers: { 'Authorization': 'pk_120226108_5A4ZTPSW5PUZ4YDQR9NP1LR2OPCA5BLX' },
  json: true
});

// Fetch waiting-on-client tasks
const waitingTasksRaw = await this.helpers.httpRequest({
  method: 'GET',
  url: `https://api.clickup.com/api/v2/team/9011968555/task?space_ids[]=${spaceId}&include_closed=false`,
  headers: { 'Authorization': 'pk_120226108_5A4ZTPSW5PUZ4YDQR9NP1LR2OPCA5BLX' },
  json: true
});

const openTasks = (openTasksRaw.tasks || []).map(t =>
  `- [${t.priority?.priority || 'normal'}] ${t.name} (Status: ${t.status?.status || 'open'})`
).join('\n') || 'No open tasks';

const waitingTasks = (waitingTasksRaw.tasks || [])
  .filter(t => t.status?.status?.toLowerCase().includes('waiting'))
  .map(t =>
    `- ${t.name} (Created: ${new Date(parseInt(t.date_created)).toLocaleDateString()})`
  ).join('\n') || 'No waiting items';

return [{
  json: {
    system_prompt: `You are a senior RevOps consultant's AI assistant. You prepare meeting agendas that make client calls highly productive. Your agendas are concise, action-oriented, and ensure nothing falls through the cracks. Style: Direct, professional, no fluff. Time-box every section. Lead with the most important items.`,
    user_prompt: `Prepare a meeting agenda for my upcoming client call.\n\n**Meeting Details:**\n- Client: ${clientData.client_name}\n- Date/Time: ${eventInfo.meeting_datetime}\n- Duration: ${eventInfo.meeting_duration} minutes\n- Attendees: ${eventInfo.attendees}\n- Update Preference: ${clientData.update_preference || 'detailed'}\n\n**Open ClickUp Tasks (sorted by priority):**\n${openTasks}\n\n**"Waiting on Client" Items:**\n${waitingTasks}\n\n**Any special context or topics I want to cover:**\n${eventInfo.manual_notes || 'None specified'}\n\n---\n\nGenerate a meeting agenda with:\n1. Quick Win / Opener (2 min) Ã¢â‚¬â€� start with a positive update\n2. Key Discussion Items (time-boxed based on priority)\n3. Blocked / Needs Client Input (be specific about what you need from them)\n4. Strategic Topics (if time allows)\n5. Action Items & Next Steps\n\nFormat as clean markdown. Include suggested time allocations that total ${eventInfo.meeting_duration} minutes.`,
    model: 'gemini-free',
    workflow_name: 'meeting-prep',
    client_name: clientData.client_name,
    purpose: 'Meeting agenda generation'
  }
}];
